import { toServerForms } from '../../server/forms/form.js';
import { toServerItemSections } from '../../server/items/section.js';
import { toServerItemLeaderboard } from './leaderboards/leaderboard.js';
export const toServerItemDetails = (sonolus, localize, toItem, details, searches, actions) => ({
    item: toItem(sonolus, localize, details.item),
    description: details.description && localize(details.description),
    actions: toServerForms(localize, details.actions, actions),
    hasCommunity: details.hasCommunity,
    leaderboards: details.leaderboards.map((leaderboard) => toServerItemLeaderboard(localize, leaderboard)),
    sections: toServerItemSections(sonolus, localize, details.sections, searches),
});
